-- DMT_V_AP_INV_LINES_DETAIL
CREATE OR REPLACE FORCE EDITIONABLE VIEW "DMT_V_AP_INV_LINES_DETAIL" ("RUN_STATUS", "ERROR_TEXT", "RECONCILIATION_STATUS", "LINE_NUMBER", "PO_NUMBER", "INVOICE_ID", "LINE_TYPE_LOOKUP_CODE", "AMOUNT", "QUANTITY_INVOICED", "UNIT_PRICE", "UNIT_OF_MEAS_LOOKUP_CODE", "DESCRIPTION", "PO_LINE_NUMBER", "PO_SHIPMENT_NUM", "PO_DISTRIBUTION_NUM", "ITEM_DESCRIPTION", "RELEASE_NUM", "PURCHASING_CATEGORY", "RECEIPT_NUMBER", "RECEIPT_LINE_NUMBER", "CONSUMPTION_ADVICE_NUMBER", "CONSUMPTION_ADVICE_LINE_NUMBER", "PACKING_SLIP", "FINAL_MATCH_FLAG", "DIST_CODE_CONCATENATED", "DISTRIBUTION_SET_NAME", "ACCOUNTING_DATE", "ACCOUNT_SEGMENT", "BALANCING_SEGMENT", "COST_CENTER_SEGMENT", "TAX_CLASSIFICATION_CODE", "SHIP_TO_LOCATION_CODE", "SHIP_FROM_LOCATION_CODE", "FINAL_DISCHARGE_LOCATION_CODE", "TRX_BUSINESS_CATEGORY", "PRODUCT_FISC_CLASSIFICATION", "PRIMARY_INTENDED_USE", "USER_DEFINED_FISC_CLASS", "PRODUCT_TYPE", "ASSESSABLE_VALUE", "PRODUCT_CATEGORY", "CONTROL_AMOUNT", "TAX_REGIME_CODE", "TAX", "TAX_STATUS_CODE", "TAX_JURISDICTION_CODE", "TAX_RATE_CODE", "TAX_RATE", "AWT_GROUP_NAME", "TYPE_1099", "INCOME_TAX_REGION", "PRORATE_ACROSS_FLAG", "LINE_GROUP_NUMBER", "COST_FACTOR_NAME", "STAT_AMOUNT", "ASSETS_TRACKING_FLAG", "ASSET_BOOK_TYPE_CODE", "ASSET_CATEGORY_ID", "SERIAL_NUMBER", "MANUFACTURER", "MODEL_NUMBER", "WARRANTY_NUMBER", "PRICE_CORRECTION_FLAG", "PRICE_CORRECT_INV_NUM", "PRICE_CORRECT_INV_LINE_NUM", "REQUESTER_FIRST_NAME", "REQUESTER_LAST_NAME", "REQUESTER_EMPLOYEE_NUM", "ATTRIBUTE_CATEGORY", "ATTRIBUTE1", "ATTRIBUTE2", "ATTRIBUTE3", "ATTRIBUTE4", "ATTRIBUTE5", "ATTRIBUTE6", "ATTRIBUTE7", "ATTRIBUTE8", "ATTRIBUTE9", "ATTRIBUTE10", "ATTRIBUTE11", "ATTRIBUTE12", "ATTRIBUTE13", "ATTRIBUTE14", "ATTRIBUTE15", "ATTRIBUTE_NUMBER1", "ATTRIBUTE_NUMBER2", "ATTRIBUTE_NUMBER3", "ATTRIBUTE_NUMBER4", "ATTRIBUTE_NUMBER5", "ATTRIBUTE_DATE1", "ATTRIBUTE_DATE2", "ATTRIBUTE_DATE3", "ATTRIBUTE_DATE4", "ATTRIBUTE_DATE5", "GLOBAL_ATTRIBUTE_CATEGORY", "GLOBAL_ATTRIBUTE1", "GLOBAL_ATTRIBUTE2", "GLOBAL_ATTRIBUTE3", "GLOBAL_ATTRIBUTE4", "GLOBAL_ATTRIBUTE5", "GLOBAL_ATTRIBUTE6", "GLOBAL_ATTRIBUTE7", "GLOBAL_ATTRIBUTE8", "GLOBAL_ATTRIBUTE9", "GLOBAL_ATTRIBUTE10", "GLOBAL_ATTRIBUTE11", "GLOBAL_ATTRIBUTE12", "GLOBAL_ATTRIBUTE13", "GLOBAL_ATTRIBUTE14", "GLOBAL_ATTRIBUTE15", "GLOBAL_ATTRIBUTE16", "GLOBAL_ATTRIBUTE17", "GLOBAL_ATTRIBUTE18", "GLOBAL_ATTRIBUTE19", "GLOBAL_ATTRIBUTE20", "GLOBAL_ATTRIBUTE_NUMBER1", "GLOBAL_ATTRIBUTE_NUMBER2", "GLOBAL_ATTRIBUTE_NUMBER3", "GLOBAL_ATTRIBUTE_NUMBER4", "GLOBAL_ATTRIBUTE_NUMBER5", "GLOBAL_ATTRIBUTE_DATE1", "GLOBAL_ATTRIBUTE_DATE2", "GLOBAL_ATTRIBUTE_DATE3", "GLOBAL_ATTRIBUTE_DATE4", "GLOBAL_ATTRIBUTE_DATE5", "PJC_PROJECT_ID", "PJC_TASK_ID", "PJC_EXPENDITURE_TYPE_ID", "PJC_EXPENDITURE_ITEM_DATE", "PJC_ORGANIZATION_ID", "PJC_PROJECT_NUMBER", "PJC_TASK_NUMBER", "PJC_EXPENDITURE_TYPE_NAME", "PJC_ORGANIZATION_NAME", "PJC_RESERVED_ATTRIBUTE1", "PJC_RESERVED_ATTRIBUTE2", "PJC_RESERVED_ATTRIBUTE3", "PJC_RESERVED_ATTRIBUTE4", "PJC_RESERVED_ATTRIBUTE5", "PJC_RESERVED_ATTRIBUTE6", "PJC_RESERVED_ATTRIBUTE7", "PJC_RESERVED_ATTRIBUTE8", "PJC_RESERVED_ATTRIBUTE9", "PJC_RESERVED_ATTRIBUTE10", "PJC_USER_DEF_ATTRIBUTE1", "PJC_USER_DEF_ATTRIBUTE2", "PJC_USER_DEF_ATTRIBUTE3", "PJC_USER_DEF_ATTRIBUTE4", "PJC_USER_DEF_ATTRIBUTE5", "PJC_USER_DEF_ATTRIBUTE6", "PJC_USER_DEF_ATTRIBUTE7", "PJC_USER_DEF_ATTRIBUTE8", "PJC_USER_DEF_ATTRIBUTE9", "PJC_USER_DEF_ATTRIBUTE10", "FISCAL_CHARGE_TYPE", "DEF_ACCTG_START_DATE", "DEF_ACCTG_END_DATE", "DEF_ACCRUAL_CODE_CONCATENATED", "PJC_PROJECT_NAME", "PJC_TASK_NAME", "PJC_WORK_TYPE", "PJC_CONTRACT_NAME", "PJC_CONTRACT_NUMBER", "PJC_FUNDING_SOURCE_NAME", "PJC_FUNDING_SOURCE_NUMBER", "REQUESTER_EMAIL_ADDRESS", "RCV_TRANSACTION_ID", "SOURCE_ID", "STG_SEQUENCE_ID", "RUN_ID", "INTEGRATION_ID", "PREFIX", "SCENARIO_ID", "STAGE_DATE", "LAST_UPDATED_DATE")  AS 
  SELECT
    -- 1. Run status
    NVL(tfm.TFM_STATUS, stg.STG_STATUS)                             AS RUN_STATUS,
    -- 2. Error text
    tfm.ERROR_TEXT                                           AS ERROR_TEXT,
    CASE
        WHEN NVL(tfm.TFM_STATUS, stg.STG_STATUS) = 'LOADED' THEN 'CONFIRMED'
        WHEN NVL(tfm.TFM_STATUS, stg.STG_STATUS) = 'FAILED' AND tfm.ERROR_TEXT IS NOT NULL THEN 'CONFIRMED'
        WHEN NVL(tfm.TFM_STATUS, stg.STG_STATUS) = 'FAILED' AND tfm.ERROR_TEXT IS NULL THEN 'UNRECONCILED'
        ELSE 'IN_PROGRESS'
    END                                                      AS RECONCILIATION_STATUS,
    -- 3. Human identifiers
    stg.LINE_NUMBER                                         AS LINE_NUMBER,
    stg.PO_NUMBER                                           AS PO_NUMBER,
    -- 4. All remaining STG business columns
    stg.INVOICE_ID,
    stg.LINE_TYPE_LOOKUP_CODE,
    stg.AMOUNT,
    stg.QUANTITY_INVOICED,
    stg.UNIT_PRICE,
    stg.UNIT_OF_MEAS_LOOKUP_CODE,
    stg.DESCRIPTION,
    stg.PO_LINE_NUMBER,
    stg.PO_SHIPMENT_NUM,
    stg.PO_DISTRIBUTION_NUM,
    stg.ITEM_DESCRIPTION,
    stg.RELEASE_NUM,
    stg.PURCHASING_CATEGORY,
    stg.RECEIPT_NUMBER,
    stg.RECEIPT_LINE_NUMBER,
    stg.CONSUMPTION_ADVICE_NUMBER,
    stg.CONSUMPTION_ADVICE_LINE_NUMBER,
    stg.PACKING_SLIP,
    stg.FINAL_MATCH_FLAG,
    stg.DIST_CODE_CONCATENATED,
    stg.DISTRIBUTION_SET_NAME,
    stg.ACCOUNTING_DATE,
    stg.ACCOUNT_SEGMENT,
    stg.BALANCING_SEGMENT,
    stg.COST_CENTER_SEGMENT,
    stg.TAX_CLASSIFICATION_CODE,
    stg.SHIP_TO_LOCATION_CODE,
    stg.SHIP_FROM_LOCATION_CODE,
    stg.FINAL_DISCHARGE_LOCATION_CODE,
    stg.TRX_BUSINESS_CATEGORY,
    stg.PRODUCT_FISC_CLASSIFICATION,
    stg.PRIMARY_INTENDED_USE,
    stg.USER_DEFINED_FISC_CLASS,
    stg.PRODUCT_TYPE,
    stg.ASSESSABLE_VALUE,
    stg.PRODUCT_CATEGORY,
    stg.CONTROL_AMOUNT,
    stg.TAX_REGIME_CODE,
    stg.TAX,
    stg.TAX_STATUS_CODE,
    stg.TAX_JURISDICTION_CODE,
    stg.TAX_RATE_CODE,
    stg.TAX_RATE,
    stg.AWT_GROUP_NAME,
    stg.TYPE_1099,
    stg.INCOME_TAX_REGION,
    stg.PRORATE_ACROSS_FLAG,
    stg.LINE_GROUP_NUMBER,
    stg.COST_FACTOR_NAME,
    stg.STAT_AMOUNT,
    stg.ASSETS_TRACKING_FLAG,
    stg.ASSET_BOOK_TYPE_CODE,
    stg.ASSET_CATEGORY_ID,
    stg.SERIAL_NUMBER,
    stg.MANUFACTURER,
    stg.MODEL_NUMBER,
    stg.WARRANTY_NUMBER,
    stg.PRICE_CORRECTION_FLAG,
    stg.PRICE_CORRECT_INV_NUM,
    stg.PRICE_CORRECT_INV_LINE_NUM,
    stg.REQUESTER_FIRST_NAME,
    stg.REQUESTER_LAST_NAME,
    stg.REQUESTER_EMPLOYEE_NUM,
    stg.ATTRIBUTE_CATEGORY,
    stg.ATTRIBUTE1,
    stg.ATTRIBUTE2,
    stg.ATTRIBUTE3,
    stg.ATTRIBUTE4,
    stg.ATTRIBUTE5,
    stg.ATTRIBUTE6,
    stg.ATTRIBUTE7,
    stg.ATTRIBUTE8,
    stg.ATTRIBUTE9,
    stg.ATTRIBUTE10,
    stg.ATTRIBUTE11,
    stg.ATTRIBUTE12,
    stg.ATTRIBUTE13,
    stg.ATTRIBUTE14,
    stg.ATTRIBUTE15,
    stg.ATTRIBUTE_NUMBER1,
    stg.ATTRIBUTE_NUMBER2,
    stg.ATTRIBUTE_NUMBER3,
    stg.ATTRIBUTE_NUMBER4,
    stg.ATTRIBUTE_NUMBER5,
    stg.ATTRIBUTE_DATE1,
    stg.ATTRIBUTE_DATE2,
    stg.ATTRIBUTE_DATE3,
    stg.ATTRIBUTE_DATE4,
    stg.ATTRIBUTE_DATE5,
    stg.GLOBAL_ATTRIBUTE_CATEGORY,
    stg.GLOBAL_ATTRIBUTE1,
    stg.GLOBAL_ATTRIBUTE2,
    stg.GLOBAL_ATTRIBUTE3,
    stg.GLOBAL_ATTRIBUTE4,
    stg.GLOBAL_ATTRIBUTE5,
    stg.GLOBAL_ATTRIBUTE6,
    stg.GLOBAL_ATTRIBUTE7,
    stg.GLOBAL_ATTRIBUTE8,
    stg.GLOBAL_ATTRIBUTE9,
    stg.GLOBAL_ATTRIBUTE10,
    stg.GLOBAL_ATTRIBUTE11,
    stg.GLOBAL_ATTRIBUTE12,
    stg.GLOBAL_ATTRIBUTE13,
    stg.GLOBAL_ATTRIBUTE14,
    stg.GLOBAL_ATTRIBUTE15,
    stg.GLOBAL_ATTRIBUTE16,
    stg.GLOBAL_ATTRIBUTE17,
    stg.GLOBAL_ATTRIBUTE18,
    stg.GLOBAL_ATTRIBUTE19,
    stg.GLOBAL_ATTRIBUTE20,
    stg.GLOBAL_ATTRIBUTE_NUMBER1,
    stg.GLOBAL_ATTRIBUTE_NUMBER2,
    stg.GLOBAL_ATTRIBUTE_NUMBER3,
    stg.GLOBAL_ATTRIBUTE_NUMBER4,
    stg.GLOBAL_ATTRIBUTE_NUMBER5,
    stg.GLOBAL_ATTRIBUTE_DATE1,
    stg.GLOBAL_ATTRIBUTE_DATE2,
    stg.GLOBAL_ATTRIBUTE_DATE3,
    stg.GLOBAL_ATTRIBUTE_DATE4,
    stg.GLOBAL_ATTRIBUTE_DATE5,
    stg.PJC_PROJECT_ID,
    stg.PJC_TASK_ID,
    stg.PJC_EXPENDITURE_TYPE_ID,
    stg.PJC_EXPENDITURE_ITEM_DATE,
    stg.PJC_ORGANIZATION_ID,
    stg.PJC_PROJECT_NUMBER,
    stg.PJC_TASK_NUMBER,
    stg.PJC_EXPENDITURE_TYPE_NAME,
    stg.PJC_ORGANIZATION_NAME,
    stg.PJC_RESERVED_ATTRIBUTE1,
    stg.PJC_RESERVED_ATTRIBUTE2,
    stg.PJC_RESERVED_ATTRIBUTE3,
    stg.PJC_RESERVED_ATTRIBUTE4,
    stg.PJC_RESERVED_ATTRIBUTE5,
    stg.PJC_RESERVED_ATTRIBUTE6,
    stg.PJC_RESERVED_ATTRIBUTE7,
    stg.PJC_RESERVED_ATTRIBUTE8,
    stg.PJC_RESERVED_ATTRIBUTE9,
    stg.PJC_RESERVED_ATTRIBUTE10,
    stg.PJC_USER_DEF_ATTRIBUTE1,
    stg.PJC_USER_DEF_ATTRIBUTE2,
    stg.PJC_USER_DEF_ATTRIBUTE3,
    stg.PJC_USER_DEF_ATTRIBUTE4,
    stg.PJC_USER_DEF_ATTRIBUTE5,
    stg.PJC_USER_DEF_ATTRIBUTE6,
    stg.PJC_USER_DEF_ATTRIBUTE7,
    stg.PJC_USER_DEF_ATTRIBUTE8,
    stg.PJC_USER_DEF_ATTRIBUTE9,
    stg.PJC_USER_DEF_ATTRIBUTE10,
    stg.FISCAL_CHARGE_TYPE,
    stg.DEF_ACCTG_START_DATE,
    stg.DEF_ACCTG_END_DATE,
    stg.DEF_ACCRUAL_CODE_CONCATENATED,
    stg.PJC_PROJECT_NAME,
    stg.PJC_TASK_NAME,
    stg.PJC_WORK_TYPE,
    stg.PJC_CONTRACT_NAME,
    stg.PJC_CONTRACT_NUMBER,
    stg.PJC_FUNDING_SOURCE_NAME,
    stg.PJC_FUNDING_SOURCE_NUMBER,
    stg.REQUESTER_EMAIL_ADDRESS,
    stg.RCV_TRANSACTION_ID,
    stg.SOURCE_ID,
    -- 5. STG_SEQUENCE_ID
    stg.STG_SEQUENCE_ID,
    -- 6. RUN_ID
    tfm.RUN_ID,
    tfm.RUN_ID                                              AS INTEGRATION_ID,
    -- 7. PREFIX (from PIPELINE_RUN)
    cm.PREFIX,
    -- 8. SCENARIO_ID
    stg.SCENARIO_ID,
    -- 9. STAGE_DATE
    stg.STAGE_DATE,
    -- 10. LAST_UPDATED_DATE
    NVL(tfm.LAST_UPDATED_DATE, stg.LAST_UPDATED_DATE)      AS LAST_UPDATED_DATE
FROM DMT_OWNER.DMT_AP_INVOICE_LINES_INT_STG_TBL stg
LEFT JOIN (
    SELECT t.*,
           ROW_NUMBER() OVER (PARTITION BY t.STG_SEQUENCE_ID
                              ORDER BY t.TFM_SEQUENCE_ID DESC) AS rn
    FROM   DMT_OWNER.DMT_AP_INVOICE_LINES_INT_TFM_TBL t
) tfm ON tfm.STG_SEQUENCE_ID = stg.STG_SEQUENCE_ID AND tfm.rn = 1
LEFT JOIN DMT_OWNER.DMT_PIPELINE_RUN_TBL cm
    ON cm.RUN_ID = tfm.RUN_ID;
